import ldap

def search_user_by_username(ldap_server, base_dn, username):
    try:
        # Connect to the LDAP server
        conn = ldap.initialize(ldap_server)
        conn.set_option(ldap.OPT_REFERRALS, 0)

        # Bind to the LDAP server (replace 'cn=admin,dc=example,dc=com' and 'password' with actual credentials)
        conn.simple_bind_s('cn=admin,dc=example,dc=com', 'password')

        # Search for the user by username
        search_filter = f"(uid={username})"
        attributes = ['uid', 'cn', 'mail']
        result_id = conn.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, attributes)

        # Retrieve the results
        entries = []
        while True:
            type_, data = conn.result(result_id, 0)
            if not data:
                break
            entries.append(data[0])

        return entries

    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")
        return []

    finally:
        # Unbind from the LDAP server
        if 'conn' in locals() and conn.bound:
            conn.unbind_s()